import { useState, useMemo } from 'react';

/**
 * ============================================================================
 * TECHNICIAN DASHBOARD COMPONENT
 * ============================================================================
 * 
 * PURPOSE:
 * Provides technicians with a prioritized view of assigned investigations.
 * Focus is on operational efficiency, not financial decisions.
 * 
 * KEY FEATURES:
 * - Priority queue of systems requiring investigation
 * - SLA tracking and urgency indicators
 * - AI guidance for investigation focus
 * - Recent activity timeline
 * - Workload summary metrics
 * 
 * DOES NOT INCLUDE:
 * - Financial data or cost analysis
 * - Replacement approval workflows
 * - Executive reports or analytics
 * 
 * BACKEND API MAPPINGS:
 * - GET /api/technician/assignments - Fetch assigned systems
 * - GET /api/technician/workload - Fetch workload metrics
 * - GET /api/technician/activity - Fetch recent activity
 * - GET /api/technician/ai-guidance - Fetch AI investigation guidance
 * - POST /api/technician/start-investigation - Begin investigation
 */

// ============================================================================
// DUMMY DATA - REPLACE WITH API CALLS
// ============================================================================

/**
 * ASSIGNED SYSTEMS
 * Backend: GET /api/technician/assignments
 */
const DUMMY_ASSIGNMENTS = [
  {
    id: 'SYS-8472',
    owner: 'Manufacturing / Line B',
    department: 'Production',
    severity: 'Critical',
    aiRootCause: 'Hardware - Disk Failure',
    confidence: 94,
    slaMinutesRemaining: 45,
    status: 'pending',
    assignedAt: new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString(),
    healthScore: 42,
    lastIncident: '2h ago'
  },
  {
    id: 'SYS-9031',
    owner: 'Data Center / Rack 7',
    department: 'IT Infrastructure',
    severity: 'High',
    aiRootCause: 'Software - Service Crash',
    confidence: 78,
    slaMinutesRemaining: 180,
    status: 'in-progress',
    assignedAt: new Date(Date.now() - 5 * 60 * 60 * 1000).toISOString(),
    healthScore: 68,
    lastIncident: '30m ago'
  },
  {
    id: 'SYS-7720',
    owner: 'R&D / Lab',
    department: 'Research',
    severity: 'Medium',
    aiRootCause: 'Hardware - Memory ECC',
    confidence: 85,
    slaMinutesRemaining: 720,
    status: 'pending',
    assignedAt: new Date(Date.now() - 8 * 60 * 60 * 1000).toISOString(),
    healthScore: 55,
    lastIncident: '4h ago'
  },
  {
    id: 'SYS-3344',
    owner: 'Customer Service / Floor 2',
    department: 'Support',
    severity: 'Critical',
    aiRootCause: 'Network - Packet Loss',
    confidence: 91,
    slaMinutesRemaining: -30, // Overdue
    status: 'overdue',
    assignedAt: new Date(Date.now() - 12 * 60 * 60 * 1000).toISOString(),
    healthScore: 38,
    lastIncident: '15m ago'
  },
  {
    id: 'SYS-5566',
    owner: 'Finance / Trading Desk',
