// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

function relativeTime(iso) {
  const seconds = Math.floor((Date.now() - new Date(iso).getTime()) / 1000);
  if (seconds < 60) return `${seconds}s ago`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  return `${Math.floor(seconds / 86400)}d ago`;
}

function formatSLA(minutes) {
  if (minutes < 0) return { text: 'OVERDUE', color: 'text-red-600', bg: 'bg-red-100', urgent: true };
  if (minutes < 60) return { text: `${minutes}m`, color: 'text-orange-600', bg: 'bg-orange-100', urgent: true };
  if (minutes < 240) return { text: `${Math.floor(minutes / 60)}h ${minutes % 60}m`, color: 'text-yellow-600', bg: 'bg-yellow-100', urgent: false };
  return { text: `${Math.floor(minutes / 60)}h`, color: 'text-green-600', bg: 'bg-green-100', urgent: false };
}

function getSeverityStyle(severity) {
  switch (severity) {
    case 'Critical':
      return 'bg-red-100 text-red-800 border-red-200';
    case 'High':
      return 'bg-orange-100 text-orange-800 border-orange-200';
    case 'Medium':
      return 'bg-yellow-100 text-yellow-800 border-yellow-200';
    case 'Low':
      return 'bg-blue-100 text-blue-800 border-blue-200';
    default:
      return 'bg-gray-100 text-gray-800 border-gray-200';
  }
}

function getStatusStyle(status) {
  switch (status) {
    case 'pending':
      return 'bg-gray-100 text-gray-800 border-gray-300';
    case 'in-progress':
      return 'bg-blue-100 text-blue-800 border-blue-300';
    case 'overdue':
      return 'bg-red-100 text-red-800 border-red-300';
    case 'completed':
      return 'bg-green-100 text-green-800 border-green-300';
    default:
      return 'bg-gray-100 text-gray-800 border-gray-300';
  }
}

